#include <cmath>
#include <algorithm>

namespace bustub {

template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : cardinality_(0), n_bits_(n_bits) {
  // Handle invalid inputs
  if (n_bits <= 0) {
    // For invalid bits, don't initialize registers
    return;
  }

  // Initialize registers
  uint32_t num_buckets = 1ULL << n_bits_;
  registers_.resize(num_buckets, 0);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  // Convert hash value to a bitset
  std::bitset<BITSET_CAPACITY> binary(hash);
  return binary;
}

template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Find the position of the first 1 bit from the left, counting from the right (1-indexed)
  for (int64_t i = BITSET_CAPACITY - 1; i >= 0; --i) {
    if (bset[i]) {
      return BITSET_CAPACITY - i;
    }
  }
  // If all zeros, return BITSET_CAPACITY + 1
  return BITSET_CAPACITY + 1;
}

template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ < 0) {
    return;
  }

  // Calculate hash
  hash_t hash = CalculateHash(val);

  // Extract bucket index from first n_bits_ (from MSB)
  uint32_t bucket = 0;
  for (int16_t i = 0; i < n_bits_; ++i) {
    bucket = (bucket << 1) | ((hash >> (BITSET_CAPACITY - 1 - i)) & 1ULL);
  }

  // Find the position of the highest set bit in the remaining bits
  // Position is calculated as: highest_bit_index + 1 (1-indexed), where index is 0-indexed from the right
  uint64_t position = 0;
  int64_t remaining_bits = BITSET_CAPACITY - n_bits_;

  // Find the highest set bit
  uint64_t highest_bit_index = -1;  // Start with -1 so that if no bit is set, position becomes 0, then we set it to remaining_bits
  for (int64_t i = remaining_bits - 1; i >= 0; --i) {
    if ((hash >> i) & 1ULL) {
      highest_bit_index = i;
      break;
    }
  }

  if (highest_bit_index == static_cast<uint64_t>(-1)) {
    // No bit is set, position equals the number of remaining bits
    position = remaining_bits;
  } else {
    // Position is highest_bit_index + 1 (count from 1, not 0)
    position = highest_bit_index + 1;
  }

  // Update register with maximum value
  {
    std::lock_guard<std::mutex> lock(mu_);
    uint8_t clamped_pos = static_cast<uint8_t>(std::min(position, static_cast<uint64_t>(255)));
    registers_[bucket] = std::max(registers_[bucket], clamped_pos);
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  if (n_bits_ < 0) {
    cardinality_ = 0;
    return;
  }

  // Calculate cardinality using HyperLogLog formula
  // E = CONSTANT * m^2 / sum(2^(-M_i))
  uint32_t m = 1ULL << n_bits_;
  double sum = 0.0;

  {
    std::lock_guard<std::mutex> lock(mu_);
    for (uint32_t i = 0; i < m; ++i) {
      sum += std::pow(2.0, -static_cast<double>(registers_[i]));
    }
  }

  double result = CONSTANT * m * m / sum;
  cardinality_ = static_cast<size_t>(result);
}

template class HyperLogLog<int64_t>;
template class HyperLogLog<std::string>;

}  // namespace bustub
